import androidx.appcompat.app.AppCompatActivity;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;

public class BankingApp extends AppCompatActivity {

    private Button transferFundsButton;
    private EditText fromAccountEditText;
    private EditText toAccountEditText;
    private EditText amountEditText;
    private TextView accountBalanceTextView;

    private double accountBalance = 1000.0;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking_app);

        transferFundsButton = findViewById(R.id.transfer_funds_button);
        fromAccountEditText = findViewById(R.id.from_account_edit_text);
        toAccountEditText = findViewById(R.id.to_account_edit_text);
        amountEditText = findViewById(R.id.amount_edit_text);
        accountBalanceTextView = findViewById(R.id.account_balance_text_view);

        accountBalanceTextView.setText("Account Balance: $" + accountBalance);

        transferFundsButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                double amount = Double.parseDouble(amountEditText.getText().toString());
                if (amount <= accountBalance) {
                    accountBalance -= amount;
                    accountBalanceTextView.setText("Account Balance: $" + accountBalance);
                } else {
                    // Display error message
                }
            }
        });
    }
}